code.Java:
import java.io.*;
import java.util.*;

public class Main {
    private static class Point {
        int x, y;
        long d2;
        Point(int x, int y) { this.x = x; this.y = y; this.d2 = 1L*x*x + 1L*y*y; }
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            Point[] pts = new Point[N];
            for (int i = 0; i < N; i++) {
                st = new StringTokenizer(br.readLine());
                int x = Integer.parseInt(st.nextToken());
                int y = Integer.parseInt(st.nextToken());
                pts[i] = new Point(x, y);
            }
            Arrays.sort(pts, (p1, p2) -> {
                if (p1.d2 != p2.d2) return Long.compare(p1.d2, p2.d2);
                if (p1.x != p2.x)   return Integer.compare(p1.x, p2.x);
                return Integer.compare(p1.y, p2.y);
            });
            for (Point p : pts) {
                out.append(p.x).append(' ').append(p.y).append('\n');
            }
        }
        System.out.print(out.toString());
    }
}

code.JavaScript:
const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = data[idx++];
let output = [];
for (let t = 0; t < T; t++) {
  const N = data[idx++];
  let points = new Array(N);
  for (let i = 0; i < N; i++) {
    const x = data[idx++];
    const y = data[idx++];
    const d2 = x * x + y * y;
    points[i] = {x, y, d2};
  }
  points.sort((a, b) => {
    if (a.d2 !== b.d2) return a.d2 - b.d2;
    if (a.x !== b.x) return a.x - b.x;
    return a.y - b.y;
  });
  for (const p of points) {
    output.push(`${p.x} ${p.y}`);
  }
}
console.log(output.join('\n'));
